export const zContentGetPath = z.object({
    accountId: z.string(),
    endpoint: z.string(),
    ids: z.array(z.string())
});

export const zContentGetQuery = z.object({
    v: z.string().optional()
});

/**
 * ContentResponse
 *
 * Content Response
 */
export const zContentGetResponse = z.object({
    meta: zResponseMeta.optional(),
    response: z.object({
        count: z.int(),
        docs: z.array(z.record(z.string(), z.unknown())).optional(),
        nextPageToken: zNextPageToken.optional()
    }).optional()
});

export const zContentListPath = z.object({
    accountId: z.string(),
    endpoint: z.string()
});

export const zContentListQuery = z.object({
    v: z.string().optional(),
    limit: z.int().lte(50).optional().default(10),
    pageToken: z.string().optional()
});

/**
 * ContentResponse
 *
 * Content Response
 */
export const zContentListResponse = z.object({
    meta: zResponseMeta.optional(),
    response: z.object({
        count: z.int(),
        docs: z.array(z.record(z.string(), z.unknown())).optional(),
        nextPageToken: zNextPageToken.optional()
    }).optional()
});
